mapper.select:
SELECT l.*, COALESCE(SUM(i.gross_pay), 0) AS total_gross, COALESCE(SUM(i.total_deduction), 0) AS total_deduction, COALESCE(SUM(i.net_pay), 0) AS total_net, COUNT(i.id)::int AS employee_count FROM erp_payroll_ledgers l LEFT JOIN erp_payroll_items i ON l.id = i.ledger_id WHERE 1=1
AND l.pay_year = #{payYear}
AND l.pay_month = #{payMonth}
AND l.status = #{status}
GROUP BY l.id ORDER BY l.pay_year DESC, l.pay_month DESC, l.created_at DESC

mapper.insert:
INSERT INTO erp_payroll_ledgers (
    id, title, pay_year, pay_month, pay_date, pay_type, start_date, end_date, status, created_by, created_at, updated_at
) VALUES (
    #{id}::uuid, #{title}, #{payYear}, #{payMonth}, #{payDate}::date, #{payType}, #{startDate}::date, #{endDate}::date, #{status}, #{createdBy}::uuid, NOW(), NOW()
)

INSERT INTO erp_payroll_items (
    id, ledger_id, employee_id, gross_pay, total_deduction, net_pay, bank_name, bank_account, bank_owner, status, memo, created_at, updated_at
) VALUES (
    #{id}::uuid, #{ledgerId}::uuid, #{employeeId}::uuid, #{grossPay}, #{totalDeduction}, #{netPay}, #{bankName}, #{bankAccount}, #{bankOwner}, #{status}, #{memo}, NOW(), NOW()
)

