SELECT 
FROM erp_payrolls p
LEFT JOIN erp_employees e ON p.employee_id = e.id
LEFT JOIN users u ON e.user_id = u.id
LEFT JOIN erp_departments d ON e.department_id = d.id


        AND p.pay_year = #{payYear}


        AND p.pay_month = #{payMonth}


        AND p.status = #{status}


ORDER BY p.pay_year DESC, p.pay_month DESC, e.employee_no ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM erp_payrolls p


        AND p.pay_year = #{payYear}


        AND p.pay_month = #{payMonth}


        AND p.status = #{status}
